import{_ as a,o as e,c as d,ag as r}from"./chunks/framework.C6K0jwmI.js";const _=JSON.parse('{"title":"店舗設定","description":"","frontmatter":{"title":"店舗設定"},"headers":[],"relativePath":"tenant/16-settings.md","filePath":"tenant/16-settings.md"}'),o={name:"tenant/16-settings.md"};function h(n,t,i,l,s,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="_16-店舗設定" tabindex="-1">16. 店舗設定 <a class="header-anchor" href="#_16-店舗設定" aria-label="Permalink to &quot;16. 店舗設定&quot;">​</a></h1><p>店舗設定では、営業時間、税率、支払い方法、レシート、テイクアウト、予約ページ、デザイン、通知などを管理します。</p><h2 id="基本設定" tabindex="-1">基本設定 <a class="header-anchor" href="#基本設定" aria-label="Permalink to &quot;基本設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>店舗名</td><td>管理画面やお客様画面に表示される店舗名</td></tr><tr><td>住所</td><td>レポート、予約、Google連携などで利用</td></tr><tr><td>営業時間</td><td>受付時間や営業日集計に影響</td></tr><tr><td>税率</td><td>会計金額に影響</td></tr><tr><td>支払い方法</td><td>現金、カード、QR決済など</td></tr></tbody></table><h2 id="営業時間と営業日" tabindex="-1">営業時間と営業日 <a class="header-anchor" href="#営業時間と営業日" aria-label="Permalink to &quot;営業時間と営業日&quot;">​</a></h2><p>深夜営業がある店舗では、営業日区切り時刻を確認してください。日報や売上集計の基準になります。</p><h2 id="レシート・領収書" tabindex="-1">レシート・領収書 <a class="header-anchor" href="#レシート・領収書" aria-label="Permalink to &quot;レシート・領収書&quot;">​</a></h2><p>店舗名、住所、登録番号、但し書き、ロゴなどを確認します。営業開始前にテスト印刷を行ってください。</p><h2 id="テイクアウト・予約ページ" tabindex="-1">テイクアウト・予約ページ <a class="header-anchor" href="#テイクアウト・予約ページ" aria-label="Permalink to &quot;テイクアウト・予約ページ&quot;">​</a></h2><p>テイクアウトや予約を利用する場合は、受付時間、受取時間、案内URL、QRコードを確認してください。</p><h2 id="スタッフ・端末管理" tabindex="-1">スタッフ・端末管理 <a class="header-anchor" href="#スタッフ・端末管理" aria-label="Permalink to &quot;スタッフ・端末管理&quot;">​</a></h2><p>スタッフアカウント、端末専用アカウント、表示する業務端末を管理します。退職や端末入替時は不要なアカウントを無効化してください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>設定が保存できない</td><td>必須項目と入力形式を確認してください。</td></tr><tr><td>税率が違う</td><td>店舗設定と商品ごとの税区分を確認してください。</td></tr><tr><td>QRコードが表示されない</td><td>対象機能が有効になっているか確認してください。</td></tr><tr><td>レシート内容が違う</td><td>店舗情報、領収書設定、プリンタ設定を確認してください。</td></tr></tbody></table>',14)])])}const p=a(o,[["render",h]]);export{_ as __pageData,p as default};
